export const ALL_NEW_ASSETS: AssetEntry[] = [
  ...KAYKIT_WEAPONS,
  ...KAYKIT_TOOLS,
  ...GEMS,
  ...FOLIAGE,
  ...ENV_PROPS,
  ...MEDIEVAL_PEOPLE,
  ...MEDIEVAL_PROPS,
  ...DUNGEON_MODULAR,
  ...WEAPON_PACK,
  ...ENCAMPMENT,
  ...MODULAR_TERRAIN,
  ...STYLOO_VILLAGE,
  ...FORTRESS,
];

export function getNewAssetById(id: string): AssetEntry | undefined {
  return ALL_NEW_ASSETS.find(a => a.id === id);
}

export function getNewAssetsByCategory(category: AssetCategory): AssetEntry[] {
  return ALL_NEW_ASSETS.filter(a => a.category === category);
}

export function searchNewAssets(query: string): AssetEntry[] {
  const q = query.toLowerCase();
  return ALL_NEW_ASSETS.filter(a =>
    a.name.toLowerCase().includes(q) ||
    a.id.includes(q) ||
    a.tags.some(t => t.includes(q))
  );
}

export type TerrainBiome = "beach" | "cave" | "cliff" | "escarpment" | "hilly" | "mountain" | "shared";

export function getTerrainByBiome(biome: TerrainBiome): AssetEntry[] {
  return MODULAR_TERRAIN.filter(a => a.tags[0] === biome);
}

export function getTerrainProps(biome?: TerrainBiome): AssetEntry[] {
  const entries = biome ? getTerrainByBiome(biome) : MODULAR_TERRAIN;
  return entries.filter(a => a.tags.includes("prop"));
}

export function getTerrainTiles(biome?: TerrainBiome): AssetEntry[] {
  const entries = biome ? getTerrainByBiome(biome) : MODULAR_TERRAIN;
  return entries.filter(a => a.tags.includes("terrain"));
}

export function getVillageBuildings(): AssetEntry[] {
  return STYLOO_VILLAGE.filter(a => a.tags.includes("building"));
}

export function getVillageDecorations(): AssetEntry[] {
  return STYLOO_VILLAGE.filter(a => !a.tags.includes("building"));
}

export function getFortressPieces(): AssetEntry[] {
  return FORTRESS;
}
